css:
.print-header {
    /* border-bottom ko hata diya taaki double line na dikhe */
    padding-bottom: 0px;
    margin-bottom: 0px; 
}

/* Naya Central Title Styling */
.central-job-title {
    text-align: center;
    font-weight: bold;
    font-size: 14px;
    text-transform: uppercase;
    padding: 5px 0; /* Isse text upar niche nahi chipkega (Vertical Gap) */
    margin-bottom: 15px; /* Neeche wale table se doori */
    letter-spacing: 1px;
}

.company-name {
    font-weight: bold;
    font-size: 16px;
    text-transform: uppercase;
    margin-top: 5px;
}

.title-box {
    text-align: right;
    font-weight: bold;
    vertical-align: bottom !important; 
}

/* Jobber Name Section - Only Top & Bottom borders */
.info-table {
    width: 100%;
    border-collapse: collapse;
    margin-bottom: 15px;
}

.info-table td {
    border-top: 1.5px solid #000;
    border-bottom: 1.5px solid #000;
    border-left: none;
    border-right: none;
    padding: 6px 8px;
    font-size: 11px;
    vertical-align: top;
}

/* Beech ki vertical separator line */
.info-table td:first-child {
    border-right: 1.5px solid #000;
}

/* Main Tables (Assembly/Components) - No Side Borders */
.data-table {
    width: 100%;
    border-collapse: collapse;
    border: none !important;
}

/* Table Header Lines */
.data-table thead tr th {
    border-top: 1.5px solid #000 !important;
    border-bottom: 1.5px solid #000 !important;
    border-left: none !important;
    border-right: none !important;
    padding: 8px 4px;
    font-size: 10px;
    text-align: center;
}

/* Table Rows - Clean look */
.data-table tbody tr td {
    border: none !important;
    padding: 6px 4px;
    font-size: 10px;
    vertical-align: top;
}

/* TOTAL ROW - Sirf Top & Bottom Borders */
.total-row td {
    border-top: 1.5px solid #000 !important;
    border-bottom: 1.5px solid #000 !important;
    border-left: none !important;
    border-right: none !important;
    font-weight: bold !important;
    padding: 4px 4px !important;
}

/* Footer Section */
.footer-section {
    margin-top: 40px;
}

.sig-box {
    border-top: 1.5px solid #000;
    text-align: center;
    width: 30%;
    display: inline-block;
    margin-right: 3%;
    padding-top: 5px;
    font-size: 11px;
    font-weight: bold;
} /* <-- Ye bracket miss ho gaya tha */

/* LOGO FIX: ERPNext ki default width:100% ko override karne ke liye */
.print-format td img {
    width: auto !important;
    max-width: 100%;
}

body:last-child .print-format td img {
    width: auto !important;
}
